-- Redbench synthetic query for TPC-H Q9
-- Feature fingerprint: tpch_q09

SELECT DISTINCT ON("lineitem"."l_orderkey", "lineitem"."l_linenumber") "lineitem"."l_shipdate" FROM "lineitem" JOIN supplier ON "lineitem"."l_suppkey" = "supplier"."s_suppkey" JOIN partsupp ON "supplier"."s_suppkey" = "partsupp"."ps_suppkey" JOIN orders ON "lineitem"."l_orderkey" = "orders"."o_orderkey" JOIN nation ON "supplier"."s_nationkey" = "nation"."n_nationkey" JOIN customer ON "nation"."n_nationkey" = "customer"."c_nationkey" WHERE "customer"."c_mktsegment" BETWEEN 'BUILDING' AND 'MACHINERY' AND "supplier"."s_acctbal" BETWEEN 654.57 AND 8572.78 AND "nation"."n_comment" BETWEEN 'haggle. carefully final deposits detect slyly agai' AND 'ss excuses cajole slyly across the packages. deposits print aroun' AND "partsupp"."ps_supplycost" BETWEEN 270.92 AND 989.97 AND "lineitem"."l_shipinstruct" BETWEEN 'COLLECT COD' AND 'TAKE BACK RETURN' AND "orders"."o_comment" BETWEEN '. requests play. even, final accounts are caref' AND 'the slyly ironic sentiments nag quickly carefully regular accounts.';
